# helper to extract assignee
assignee_re1 = re.compile(r"^(?P<assignee>[A-Z0-9 &\.,'\-()]+?)\s+(?:holds|hold|is owned by|is assigned to|owns|assigned to|owned by|owns the|is the owner|has)\b", re.I)
