    m = re.search(r"^([A-Z0-9 &'`.,\-()]+?)\s+(?:HOLDS|HOLD|IS OWNED BY|IS ASSIGNED TO|OWNS|ASSIGNED TO|OWNED BY|IS THE OWNER|HAS)\b", text.upper())
